definitions.query:
#graphql
mutation OwnerMetafieldHydrationDefinitionsCreate(
  $location: MetafieldDefinitionInput!
  $page: MetafieldDefinitionInput!
  $article: MetafieldDefinitionInput!
  $market: MetafieldDefinitionInput!
) {
  location: metafieldDefinitionCreate(definition: $location) {
    createdDefinition { id }
    userErrors { field message code }
  }
  page: metafieldDefinitionCreate(definition: $page) {
    createdDefinition { id }
    userErrors { field message code }
  }
  article: metafieldDefinitionCreate(definition: $article) {
    createdDefinition { id }
    userErrors { field message code }
  }
  market: metafieldDefinitionCreate(definition: $market) {
    createdDefinition { id }
    userErrors { field message code }
  }
}

contentCreate.query:
mutation OnlineStoreContentCreate($blog: BlogCreateInput!, $page: PageCreateInput!) {
  blogCreate(blog: $blog) {
    blog {
      id
      title
      handle
      commentPolicy
      templateSuffix
      tags
      articlesCount {
        count
        precision
      }
    }
    userErrors {
      field
      message
    }
  }
  pageCreate(page: $page) {
    page {
      id
      title
      handle
      body
      bodySummary
      isPublished
      templateSuffix
    }
    userErrors {
      field
      message
    }
  }
}

articleCreate.query:
mutation OnlineStoreContentArticleCreate($article: ArticleCreateInput!) {
  articleCreate(article: $article) {
    article {
      id
      title
      handle
      body
      summary
      tags
      isPublished
      templateSuffix
      author {
        name
      }
      blog {
        id
        title
        handle
        commentPolicy
        createdAt
        updatedAt
      }
      commentsCount {
        count
        precision
      }
    }
    userErrors {
      field
      message
    }
  }
}

